using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

/// <summary>
/// Helper to create in-memory SchoolContext instances for testing.
/// </summary>
public static class TestDbContextFactory
{
    public static SchoolContext Create(string databaseName = null)
    {
        databaseName ??= Guid.NewGuid().ToString();

        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static SchoolContext CreateWithStudents(string databaseName = null)
    {
        var context = Create(databaseName);
        SeedStudents(context);
        return context;
    }

    public static SchoolContext CreateWithFullData(string databaseName = null)
    {
        var context = Create(databaseName);
        SeedStudents(context);
        SeedInstructors(context);
        SeedDepartments(context);
        SeedCourses(context);
        return context;
    }

    private static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) }
        );
        context.SaveChanges();
    }

    private static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) },
            new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6) }
        );
        context.SaveChanges();
    }

    private static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = 10 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1), InstructorID = 11 }
        );
        context.SaveChanges();
    }

    private static void SeedCourses(SchoolContext context)
    {
        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
        );
        context.SaveChanges();
    }
}

using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.Equal(2, result.PageIndex);
    }

    [Fact]
    public void Constructor_CalculatesTotalPages_Correctly()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.Equal(4, result.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_CalculatesTotalPages_ExactDivision()
    {
        // Arrange
        var items = new List<string> { "a", "b" };

        // Act
        var result = new PaginatedList<string>(items, 6, 1, 3);

        // Assert
        Assert.Equal(2, result.TotalPages); // ceil(6/3) = 2
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var result = new PaginatedList<int>(items, 10, 1, 5);

        // Assert
        Assert.Equal(3, result.Count);
        Assert.Contains(1, result);
        Assert.Contains(2, result);
        Assert.Contains(3, result);
    }

    [Fact]
    public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
    {
        // Arrange
        var items = new List<string> { "a" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
    {
        // Arrange
        var items = new List<string> { "a" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 5);

        // Assert
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_ReturnsFalse_WhenOnLastPage()
    {
        // Arrange
        var items = new List<string> { "a" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 5); // TotalPages = 2

        // Assert
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
    {
        // Arrange
        var items = new List<string> { "a" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 5); // TotalPages = 2

        // Assert
        Assert.True(result.HasNextPage);
    }

    [Theory]
    [InlineData(1, 3, 10, 4)]   // ceil(10/3) = 4
    [InlineData(1, 5, 25, 5)]   // ceil(25/5) = 5
    [InlineData(1, 10, 1, 1)]   // ceil(1/10) = 1
    [InlineData(1, 1, 5, 5)]    // ceil(5/1) = 5
    public void Constructor_TotalPages_VariousInputs(int pageIndex, int pageSize, int count, int expectedTotalPages)
    {
        // Act
        var result = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Assert
        Assert.Equal(expectedTotalPages, result.TotalPages);
    }

    [Fact]
    public void Create_ReturnsCorrectPage_FirstPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(5, result[4]);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(4, result.TotalPages); // ceil(20/5) = 4
    }

    [Fact]
    public void Create_ReturnsCorrectPage_MiddlePage()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(6, result[0]);
        Assert.Equal(10, result[4]);
        Assert.Equal(2, result.PageIndex);
    }

    [Fact]
    public void Create_ReturnsCorrectPage_LastPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 4, 5);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(16, result[0]);
        Assert.Equal(20, result[4]);
        Assert.Equal(4, result.PageIndex);
        Assert.False(result.HasNextPage);
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void Create_ReturnsPartialLastPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.Equal(2, result.Count); // only 2 items on page 2
        Assert.Equal(6, result[0]);
        Assert.Equal(7, result[1]);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.Equal(1, result.PageIndex);
    }
}

using ContosoUniversity.Models;
