namespace ContosoUniversity.Tests;

public class NotificationServiceTests
{
    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Course (ID: 42)", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesNameBasedMessage()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Student 'John Doe'", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("deleted", notification.Message);
        Assert.Contains("Department 'Engineering'", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUser_SetsSystemAsCreatedBy()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var service = new NotificationService();
        var before = DateTime.Now;

        // Act
        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        var result = service.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        // Arrange
        var service = new NotificationService();
        service.SendNotification("First", "1", "First Item", EntityOperation.CREATE, "Admin");
        service.SendNotification("Second", "2", "Second Item", EntityOperation.UPDATE, "Admin");

        // Act
        var first = service.ReceiveNotification();
        var second = service.ReceiveNotification();

        // Assert
        Assert.Equal("First", first.EntityType);
        Assert.Equal("Second", second.EntityType);
    }

    [Fact]
    public void ReceiveNotification_RemovesItemFromQueue()
    {
        // Arrange
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "Admin");

        // Act
        var first = service.ReceiveNotification();
        var second = service.ReceiveNotification();

        // Assert
        Assert.NotNull(first);
        Assert.Null(second);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert - should not throw
        var exception = Record.Exception(() => service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var service = new NotificationService();

        // Act & Assert
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_AllEnqueued()
    {
        // Arrange
        var service = new NotificationService();

        // Act
        for (int i = 0; i < 5; i++)
        {
            service.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE, "Admin");
        }

        // Assert
        for (int i = 0; i < 5; i++)
        {
            var notification = service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal(i.ToString(), notification.EntityId);
        }
        Assert.Null(service.ReceiveNotification());
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_AllOperations_GenerateCorrectMessage(EntityOperation operation, string expectedVerb)
    {
        // Arrange
        var service = new NotificationService();

        // Act
        service.SendNotification("Entity", "1", "Test Entity", operation, "Admin");

        // Assert
        var notification = service.ReceiveNotification();
        Assert.Contains(expectedVerb, notification.Message);
    }
}

