+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using Microsoft.EntityFrameworkCore;
+using Xunit;
+
+namespace ContosoUniversity.Tests;
+
+public class SchoolContextTests
+{
+    [Fact]
+    public void SchoolContext_CanCreateWithInMemoryProvider()
+    {
+        // Arrange & Act
+        using var context = TestDbContextFactory.Create();
+
+        // Assert
+        Assert.NotNull(context);
+        Assert.NotNull(context.Students);
+        Assert.NotNull(context.Courses);
+        Assert.NotNull(context.Departments);
+        Assert.NotNull(context.Instructors);
+        Assert.NotNull(context.Enrollments);
+        Assert.NotNull(context.CourseAssignments);
+        Assert.NotNull(context.OfficeAssignments);
+        Assert.NotNull(context.Notifications);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddAndRetrieveStudent()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        var student = new Student
+        {
+            FirstMidName = "Test",
+            LastName = "Student",
+            EnrollmentDate = new DateTime(2023, 9, 1)
+        };
+
+        // Act
+        context.Students.Add(student);
+        context.SaveChanges();
+
+        // Assert
+        var retrieved = context.Students.First(s => s.LastName == "Student");
+        Assert.Equal("Test", retrieved.FirstMidName);
+        Assert.Equal(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
+    }
+
+    [Fact]
+    public void SchoolContext_CourseAssignment_HasCompositeKey()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        context.Instructors.Add(new Instructor { ID = 1, FirstMidName = "Test", LastName = "Instructor", HireDate = DateTime.Now });
+        context.Courses.Add(new Course { CourseID = 100, Title = "TestCourse", Credits = 3, DepartmentID = 1 });
+        context.SaveChanges();
+
+        // Act
+        context.CourseAssignments.Add(new CourseAssignment { InstructorID = 1, CourseID = 100 });
+        context.SaveChanges();
+
+        // Assert
+        var assignment = context.CourseAssignments.Find(100, 1);
+        Assert.NotNull(assignment);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddAndRetrieveDepartment()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        var department = new Department
+        {
+            Name = "Physics",
+            Budget = 250000,
+            StartDate = new DateTime(2023, 1, 1)
+        };
+
+        // Act
+        context.Departments.Add(department);
+        context.SaveChanges();
+
+        // Assert
+        var retrieved = context.Departments.First(d => d.Name == "Physics");
+        Assert.Equal(250000, retrieved.Budget);
+    }
+
+    [Fact]
+    public void SchoolContext_InstructorOfficeAssignment_OneToOne()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        var instructor = new Instructor
+        {
+            ID = 50,
+            FirstMidName = "Test",
+            LastName = "Prof",
+            HireDate = DateTime.Now,
+            OfficeAssignment = new OfficeAssignment { InstructorID = 50, Location = "Room 101" }
+        };
+
+        // Act
+        context.Instructors.Add(instructor);
+        context.SaveChanges();
+
+        // Assert
+        var retrieved = context.Instructors.Include(i => i.OfficeAssignment).First(i => i.ID == 50);
+        Assert.NotNull(retrieved.OfficeAssignment);
+        Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
+    }
+
+    [Fact]
+    public void SchoolContext_CanAddNotification()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        var notification = new Notification
+        {
+            EntityType = "Student",
+            EntityId = "1",
+            Operation = "CREATE",
+            Message = "New student created",
+            CreatedAt = DateTime.Now,
+            CreatedBy = "Admin",
+            IsRead = false
+        };
+
+        // Act
+        context.Notifications.Add(notification);
+        context.SaveChanges();
+
+        // Assert
+        var retrieved = context.Notifications.First();
+        Assert.Equal("Student", retrieved.EntityType);
+        Assert.Equal("CREATE", retrieved.Operation);
+    }
+
+    [Fact]
+    public void SchoolContext_StudentEnrollmentRelationship()
+    {
+        // Arrange
+        using var context = TestDbContextFactory.Create();
+        var student = new Student
+        {
+            ID = 100,
+            FirstMidName = "Test",
+            LastName = "Student",
+            EnrollmentDate = DateTime.Now
+        };
+        var course = new Course { CourseID = 200, Title = "TestCourse", Credits = 3, DepartmentID = 1 };
+        context.Students.Add(student);
+        context.Courses.Add(course);
+        context.SaveChanges();
+
+        context.Enrollments.Add(new Enrollment { StudentID = 100, CourseID = 200, Grade = Grade.A });
+        context.SaveChanges();
+
+        // Assert
+        var enrollment = context.Enrollments.First(e => e.StudentID == 100);
+        Assert.Equal(Grade.A, enrollment.Grade);
+        Assert.Equal(200, enrollment.CourseID);
+    }
+}
