using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests;

/// <summary>
/// Tests for NotificationService. Note: The service uses a static ConcurrentQueue,
/// so tests must be run sequentially and must drain the queue before asserting.
/// We use a unique marker per test to identify our own notifications.
/// </summary>
[Collection("NotificationServiceTests")]
public class NotificationServiceTests
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from other tests
        DrainQueue();
    }

    private void DrainQueue()
    {
        while (_service.ReceiveNotification() != null) { }
    }

    [Fact]
    public void SendNotification_EnqueuesNotification()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        // Act
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Course (ID: 42)", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithDisplayName_GeneratesNameBasedMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("Student 'John Doe'", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("deleted", notification.Message);
        Assert.Contains("Department 'Engineering'", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUser_SetsSystemAsCreatedBy()
    {
        // Act
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [Fact]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        // Queue is drained in constructor

        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        // Act
        _service.SendNotification("FirstType", "100", "First Item", EntityOperation.CREATE, "Admin");
        _service.SendNotification("SecondType", "200", "Second Item", EntityOperation.UPDATE, "Admin");

        // Assert
        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        Assert.Equal("FirstType", first.EntityType);
        Assert.Equal("SecondType", second.EntityType);
    }

    [Fact]
    public void ReceiveNotification_RemovesItemFromQueue()
    {
        // Arrange
        _service.SendNotification("UniqueTest", "999", "Test Item", EntityOperation.CREATE, "Admin");

        // Act
        var first = _service.ReceiveNotification();

        // Assert
        Assert.NotNull(first);
        Assert.Equal("UniqueTest", first.EntityType);
        // Verify queue is now empty (no more of our items)
        // Note: Other concurrent tests could have added items, so we just verify our item was dequeued
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - should not throw
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var exception = Record.Exception(() => _service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_AllEnqueued()
    {
        // Arrange - use a unique entity type to identify our notifications
        var marker = Guid.NewGuid().ToString();

        // Act
        for (int i = 0; i < 5; i++)
        {
            _service.SendNotification(marker, i.ToString(), $"Student {i}", EntityOperation.CREATE, "Admin");
        }

        // Assert - collect our notifications
        var collected = new List<Notification>();
        Notification n;
        while ((n = _service.ReceiveNotification()) != null)
        {
            if (n.EntityType == marker)
                collected.Add(n);
        }
        Assert.Equal(5, collected.Count);
        for (int i = 0; i < 5; i++)
        {
            Assert.Equal(i.ToString(), collected[i].EntityId);
        }
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_AllOperations_GenerateCorrectMessage(EntityOperation operation, string expectedVerb)
    {
        // Act
        _service.SendNotification("Entity", "1", "Test Entity", operation, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message);
    }
}

